// Combine transcript segments into clean text
const episode = $('Code in JavaScript').item.json;
let transcript = '';

try {
  const transcriptData = $input.first().json;

  // Handle different transcript response formats
  if (transcriptData.transcripts) {
    // youtube-transcript.io format
    transcript = transcriptData.transcripts
      .map(t => t.text || t.snippet || '')
      .join(' ')
      .replace(/\s+/g, ' ')
      .trim();
  } else if (transcriptData.transcript) {
    // Alternative format
    if (Array.isArray(transcriptData.transcript)) {
      transcript = transcriptData.transcript
        .map(t => t.text || t.snippet || '')
        .join(' ')
        .replace(/\s+/g, ' ')
        .trim();
    } else {
      transcript = transcriptData.transcript;
    }
  } else if (Array.isArray(transcriptData)) {
    transcript = transcriptData
      .map(t => t.text || t.snippet || '')
      .join(' ')
      .replace(/\s+/g, ' ')
      .trim();
  }
} catch(e) {
  // If transcript fetch failed, use the video description as fallback
  transcript = episode.description || 'Transcript not available.';
}

// Truncate if too long (Claude has context limits)
if (transcript.length > 80000) {
  transcript = transcript.substring(0, 80000) + '... [transcript truncated]';
}

return [{ json: { ...episode, transcript } }];

// Parse Claude's tool_use response. Anthropic guarantees the input
// object matches the tool's input_schema, so JSON parse failures from
// unescaped quotes in free-text JSON (the original bug) are impossible.
const episode = $('Clean Transcript').item.json;
const claudeResponse = $input.first().json;

if (!Array.isArray(claudeResponse.content)) {
  throw new Error('Claude response missing content array: ' + JSON.stringify(claudeResponse).slice(0, 400));
}
const toolUse = claudeResponse.content.find(b => b.type === 'tool_use' && b.name === 'generate_blog_post');
if (!toolUse) {
  throw new Error('Claude did not return a generate_blog_post tool_use block. stop_reason=' +
    (claudeResponse.stop_reason || 'unknown') + ' content_types=' +
    JSON.stringify(claudeResponse.content.map(b => b.type)));
}
const blogData = toolUse.input;
if (!blogData || typeof blogData !== 'object') {
  throw new Error('tool_use.input is not an object: ' + JSON.stringify(toolUse).slice(0, 400));
}

// Build the complete blog post object (same shape as before).
const post = {
  slug: episode.slug,
  title: blogData.title || episode.title,
  episodeNumber: blogData.episodeNumber || 0,
  guestName: blogData.guestName || '',
  guestBio: blogData.guestBio || '',
  publishedAt: episode.publishedAt,
  duration: episode.durationFormatted,
  thumbnail: episode.thumbnail,
  youtubeUrl: episode.youtubeUrl,
  spotifyUrl: 'https://open.spotify.com/show/03FuFRyzkaWhZkk5yxFePJ',
  appleUrl: 'https://podcasts.apple.com/us/podcast/the-manage-her/id1809208475',
  excerpt: blogData.excerpt || '',
  metaDescription: blogData.metaDescription || '',
  topics: blogData.topics || [],
  keyTakeaways: blogData.keyTakeaways || [],
  guestLinks: blogData.guestLinks || [],
  pullQuotes: blogData.pullQuotes || [],
  timestamps: blogData.timestamps || [],
  quiz: blogData.quiz || null,
  transcript: $('Clean Transcript').first().json.transcript || '',
  content: blogData.content || ''
};

const indexEntry = {
  slug: post.slug,
  title: post.title,
  episodeNumber: post.episodeNumber,
  guestName: post.guestName,
  publishedAt: post.publishedAt,
  duration: post.duration,
  thumbnail: post.thumbnail,
  excerpt: post.excerpt,
  topics: post.topics,
  youtubeUrl: post.youtubeUrl
};

return [{ json: { post, indexEntry, slug: episode.slug } }];

// Process episodes from the webhook response
const episodes = $input.first().json.episodes || [];

function makeSlug(title) {
  return title
    .toLowerCase()
    .replace(/^ep\.?\s*\d+\s*:?\s*/i, '')
    .replace(/\|.*$/g, '')
    .replace(/the manage her:?\s*/gi, '')
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .substring(0, 120);
}

function formatDuration(iso) {
  const match = (iso || '').match(/PT(?:(\d+)H)?(?:(\d+)M)?(?:(\d+)S)?/);
  if (!match) return '30 min';
  const h = parseInt(match[1]||0);
  const m = parseInt(match[2]||0);
  if (h > 0) return `${h}h ${m}m`;
  return `${m} min`;
}

// Filter out YouTube Shorts (under 120 seconds)
const filtered = episodes.filter(ep => {
  const match = (ep.duration || '').match(/PT(?:(\d+)H)?(?:(\d+)M)?(?:(\d+)S)?/);
  if (!match) return true;
  const totalSeconds = (parseInt(match[1]||0) * 3600) + (parseInt(match[2]||0) * 60) + parseInt(match[3]||0);
  return totalSeconds >= 120;
});

// Return each episode as a separate item
return filtered.slice(0, 5).map(ep => ({
  json: {
    id: ep.id,
    title: ep.title,
    slug: makeSlug(ep.title),
    description: ep.description,
    thumbnail: ep.thumbnailMax || ep.thumbnail,
    publishedAt: ep.publishedAt,
    duration: ep.duration,
    durationFormatted: formatDuration(ep.duration),
    youtubeUrl: `https://www.youtube.com/watch?v=${ep.id}`
  }
}));

const episode = $input.first().json;

const prompt = `You are a blog content writer for The Manage Her® — a women's leadership podcast hosted by Aimee Rickabus, CEO of a nine-figure technology company, bestselling author, and mother of six. Generate an enhanced show notes blog post from this podcast episode by calling the generate_blog_post tool.

EPISODE DETAILS:
Title: ${episode.title}
Duration: ${episode.durationFormatted}
Published: ${episode.publishedAt}
YouTube URL: ${episode.youtubeUrl}

EPISODE DESCRIPTION:
${(episode.description || '').substring(0, 8000)}

TRANSCRIPT:
${(episode.transcript || '').substring(0, 50000)}

WRITING GUIDANCE:
- title: SEO-friendly, under 80 characters, different from the episode title
- episodeNumber: extract from the title or use 0 if absent
- guestName: full name or empty string for solo episodes
- guestBio: 2-3 sentence bio based on what's discussed
- excerpt: 2-3 sentence summary that makes someone want to listen
- metaDescription: SEO meta description under 160 characters
- topics: 3-5 from the enum (Leadership, Motherhood, Financial Literacy, Wellness, Entrepreneurship, Boundaries, Identity, Marriage, Community, Spirituality)
- keyTakeaways: 5-7 complete-sentence takeaways
- guestLinks: extract Instagram/LinkedIn/TikTok/YouTube/website URLs from the description
- pullQuotes: 3-5 memorable quotes; timestamp empty if unknown
- timestamps: chapter markers from the transcript/description
- content: 800-1200 words of HTML using p/strong/em/h3 tags. Brand voice: bold, warm, direct, permission-giving. Address reader as "you". No bullet lists.
- quiz: a SELF-DISCOVERY quiz (not knowledge test) with empowering archetype names tied to the episode. types.A/B/C/D each have a name (2-4 word archetype) and a 3-4 sentence personalized description in second person ending with why they should listen. questions: EXACTLY 6 questions, each with EXACTLY 4 options. Each option's type is A/B/C/D. All options should feel valid; this is self-discovery, not right/wrong.`;

const tool = {
  name: "generate_blog_post",
  description: "Generate the structured blog post for this episode.",
  input_schema: {"type":"object","additionalProperties":false,"required":["title","episodeNumber","guestName","excerpt","metaDescription","topics","keyTakeaways","content","quiz"],"properties":{"title":{"type":"string","maxLength":100},"episodeNumber":{"type":"integer","minimum":0},"guestName":{"type":"string"},"guestBio":{"type":"string"},"excerpt":{"type":"string","maxLength":400},"metaDescription":{"type":"string","maxLength":200},"topics":{"type":"array","minItems":1,"maxItems":5,"items":{"type":"string","enum":["Leadership","Motherhood","Financial Literacy","Wellness","Entrepreneurship","Boundaries","Identity","Marriage","Community","Spirituality"]}},"keyTakeaways":{"type":"array","minItems":3,"maxItems":8,"items":{"type":"string"}},"guestLinks":{"type":"array","items":{"type":"object","additionalProperties":false,"required":["label","url"],"properties":{"label":{"type":"string"},"url":{"type":"string"}}}},"pullQuotes":{"type":"array","items":{"type":"object","additionalProperties":false,"required":["text"],"properties":{"text":{"type":"string"},"timestamp":{"type":"string"}}}},"timestamps":{"type":"array","items":{"type":"object","additionalProperties":false,"required":["time","label"],"properties":{"time":{"type":"string"},"label":{"type":"string"}}}},"content":{"type":"string"},"quiz":{"type":"object","additionalProperties":false,"required":["title","description","types","questions"],"properties":{"title":{"type":"string"},"description":{"type":"string"},"types":{"type":"object","additionalProperties":false,"required":["A","B","C","D"],"properties":{"A":{"type":"object","additionalProperties":false,"required":["name","description"],"properties":{"name":{"type":"string"},"description":{"type":"string"}}},"B":{"type":"object","additionalProperties":false,"required":["name","description"],"properties":{"name":{"type":"string"},"description":{"type":"string"}}},"C":{"type":"object","additionalProperties":false,"required":["name","description"],"properties":{"name":{"type":"string"},"description":{"type":"string"}}},"D":{"type":"object","additionalProperties":false,"required":["name","description"],"properties":{"name":{"type":"string"},"description":{"type":"string"}}}}},"questions":{"type":"array","minItems":6,"maxItems":6,"items":{"type":"object","additionalProperties":false,"required":["question","options"],"properties":{"question":{"type":"string"},"options":{"type":"array","minItems":4,"maxItems":4,"items":{"type":"object","additionalProperties":false,"required":["text","type"],"properties":{"text":{"type":"string"},"type":{"type":"string","enum":["A","B","C","D"]}}}}}}}}}}}
};

const requestBody = {
  model: "claude-sonnet-4-6",
  max_tokens: 10000,
  tools: [tool],
  tool_choice: { type: "tool", name: "generate_blog_post" },
  messages: [{ role: "user", content: prompt }]
};

return [{ json: { ...episode, claudeRequestBody: JSON.stringify(requestBody) } }];

